from pymongo import MongoClient
import sys

class MongoDBAdvancedFilter:
    def __init__(self, connection_string, database_name):
        self.client = MongoClient(connection_string)
        self.db = self.client[database_name]
    
    def execute_where_query(self, collection_name, javascript_expression):
        try:
            collection = self.db[collection_name]
            results = collection.find({"$where": javascript_expression})
            return list(results)
        except Exception as e:
            print(f"Error executing query: {e}")
            return []
    
    def execute_user_filter(self, collection_name, user_filter):
        try:
            collection = self.db[collection_name]
            results = collection.find({"$where": user_filter})
            return list(results)
        except Exception as e:
            print(f"Error executing user filter: {e}")
            return []

